import{c as t,a0 as s,U as d,j as r,g as o,n,o as c,m as l}from"./chunks/framework.Dvkoa_vi.js";const T=JSON.parse('{"title":"Respuestas — Sesión 4: Modelos y primer API","description":"Solucionario razonado del test de 22 preguntas de la Sesión 4.","frontmatter":{"title":"Respuestas — Sesión 4: Modelos y primer API","description":"Solucionario razonado del test de 22 preguntas de la Sesión 4.","outline":[2,2],"search":false},"headers":[],"relativePath":"02-dotnet/test/sesion-04/respuestas.md","filePath":"02-dotnet/test/sesion-04/respuestas.md"}'),i={name:"02-dotnet/test/sesion-04/respuestas.md"};function p(u,e,m,g,v,b){const a=s("CopyOrDownloadAsMarkdownButtons");return d(),r("div",null,[e[0]||(e[0]=o("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /curso-normalizacion/02-dotnet\\test\\sesion-04\\respuestas.md for this page in Markdown format",-1)),e[1]||(e[1]=o("h1",{id:"respuestas-—-test-sesion-4-modelos-y-primer-api",tabindex:"-1"},[n("Respuestas — Test Sesión 4: Modelos y primer API "),o("a",{class:"header-anchor",href:"#respuestas-—-test-sesion-4-modelos-y-primer-api","aria-label":"Permalink to “Respuestas — Test Sesión 4: Modelos y primer API”"},"​")],-1)),c(a),e[2]||(e[2]=l("<ol><li><p><strong>c)</strong> El DTO transporta datos entre capas sin lógica de negocio; la entidad representa una fila de la BD con mapeo directo. Los DTOs son objetos planos con solo propiedades, sin métodos de acceso a datos ni lógica de negocio.</p></li><li><p><strong>c)</strong> Valida automáticamente el ModelState y devuelve 400 si no es válido. Con <code>[ApiController]</code>, si un DTO tiene DataAnnotations y los datos no son válidos, .NET devuelve un <code>ValidationProblemDetails</code> sin escribir código de validación en la acción.</p></li><li><p><strong>b)</strong> <code>/api/Herramientas/activas</code>. El placeholder <code>[controller]</code> se reemplaza por el nombre del controlador sin el sufijo &quot;Controller&quot;, y <code>&quot;activas&quot;</code> es la subruta del <code>[HttpGet]</code>.</p></li><li><p><strong>c)</strong> 404. El método <code>NotFound()</code> de <code>ControllerBase</code> devuelve un HTTP 404 Not Found.</p></li><li><p><strong>d)</strong> POST. En REST, POST se usa para crear recursos nuevos, mientras que PUT se usa para actualizar recursos existentes.</p></li><li><p><strong>c)</strong> 404 Not Found. <code>FirstOrDefault</code> devuelve null si no encuentra el elemento, y el <code>if</code> comprueba null para devolver <code>NotFound()</code>.</p></li><li><p><strong>d)</strong> <code>ControladorBase</code>. Es la clase base UA que extiende <code>ControllerBase</code> (y <code>ApiControllerBase</code>) y agrega <code>HandleResult</code>, <code>CodPer</code>, <code>Idioma</code>, <code>Roles</code> y <code>NombrePersona</code>. <code>ControllerBase</code> es la clase estándar de ASP.NET Core, pero el patrón UA requiere la subclase <code>ControladorBase</code>.</p></li><li><p><strong>b)</strong> Un JSON con formato <code>ProblemDetails</code> (RFC 9457). El método <code>Problem()</code> genera una respuesta estándar con campos <code>type</code>, <code>title</code>, <code>status</code> y <code>detail</code>. (El detalle completo del flujo <code>Result&lt;T&gt;</code> → <code>ProblemDetails</code> se ve en la sesión 16.)</p></li><li><p><strong>b)</strong> .NET devuelve automáticamente un 400 Bad Request con <code>ValidationProblemDetails</code>. El atributo <code>[ApiController]</code> intercepta el ModelState inválido antes de que se ejecute la acción del controlador.</p></li><li><p><strong>b)</strong> La ruta debería ser <code>&quot;api/[controller]&quot;</code> con corchetes para usar el nombre del controlador. Sin corchetes, la ruta literal sería <code>/api/controller</code> en vez de <code>/api/Reservas</code>.</p></li><li><p><strong>b)</strong> <code>[Range(5, 120)]</code>. Este atributo valida que el valor numérico esté entre el mínimo y máximo indicados. <code>[MinLength]</code>/<code>[MaxLength]</code> son para longitud de strings o colecciones.</p></li><li><p><strong>b)</strong> Solo <code>NombreEs</code>. Es el único campo con <code>[Required]</code>. <code>Granularidad</code> tiene <code>[Range]</code> pero no <code>[Required]</code> (aunque al ser <code>int</code> no puede ser null, el valor 0 pasaría sin <code>[Range]</code>). <code>EmailContacto</code> valida formato solo si tiene valor.</p></li><li><p><strong>b)</strong> El tipo de retorno es <code>IActionResult</code> pero se devuelve una lista directamente sin envolverla en <code>Ok()</code>. Se necesita <code>return Ok(_reservas);</code> para que se serialice correctamente con código 200.</p></li><li><p><strong>c)</strong> <code>[FromBody]</code>. Este atributo indica que el parámetro se deserializa del cuerpo de la petición HTTP (típicamente JSON). <code>[FromQuery]</code> es para parámetros de URL y <code>[FromRoute]</code> para segmentos de la ruta.</p></li><li><p><strong>a)</strong> <code>Ok()</code> devuelve 200 con datos y <code>NoContent()</code> devuelve 204 sin datos. El 204 se usa cuando la operación fue exitosa pero no hay contenido que devolver (ej: un <code>DELETE</code> o un <code>PUT</code> exitosos).</p></li><li><p><strong>b)</strong> En <code>Models/</code> con prefijo <code>Clase</code> (ej: <code>ClasePermiso</code>) y propiedades en PascalCase. Es la convención UA: nombres en español, prefijo <code>Clase</code>, carpeta <code>Models/</code> organizada por entidad.</p></li><li><p><strong>b)</strong> No hereda de <code>ControllerBase</code>, por lo que <code>Ok()</code> no está disponible. Sin la herencia, el método <code>Ok()</code> y otros métodos helper de HTTP no están accesibles en el controlador.</p></li><li><p><strong>c)</strong> PUT. En REST, PUT se usa para reemplazar completamente un recurso existente. PATCH se usa para actualizaciones parciales.</p></li><li><p><strong>b)</strong> <code>public ActionResult&lt;ClaseEcoUnidad&gt; Eco([FromBody] ClaseEcoUnidad dto)</code>. Usa <code>ActionResult&lt;T&gt;</code> para tipar la respuesta y <code>[FromBody]</code> para deserializar el body JSON al DTO.</p></li><li><p><strong>b)</strong> <code>[Produces(&quot;application/json&quot;)]</code>. Este atributo declara el content-type de las respuestas y es útil para la documentación OpenAPI/Scalar.</p></li><li><p><strong>b)</strong> Documenta que la acción puede devolver un 500 con formato <code>ProblemDetails</code> (para OpenAPI/Scalar). Es un atributo declarativo para la generación de documentación, no afecta al comportamiento en runtime.</p></li><li><p><strong>b)</strong> <code>return Ok(_reservas.Where(r =&gt; r.Activo));</code>. Se envuelve el resultado filtrado en <code>Ok()</code> para devolver un 200 con la lista serializada como JSON. Las opciones a), c) y d) no usan el patrón estándar de <code>IActionResult</code> en el patrón UA.</p></li></ol>",1))])}const E=t(i,[["render",p]]);export{T as __pageData,E as default};
